noncompliant:
// Noncompliant: Function with noreturn attribute that returns
__attribute__((noreturn)) int badFunction(int x) {
  if (x > 0) {
    return x;  // This should not happen in a noreturn function
  }
  exit(1);
}

compliant:
// Compliant: Function with noreturn attribute that never returns
__attribute__((noreturn)) void goodFunction(int x) {
  if (x > 0) {
    exit(x);
  } else {
    abort();
  }
  // No return statement - function always exits
}

// Alternative: Function without noreturn that can return
int returningFunction(int x) {
  if (x > 0) {
    return x;
  }
  return -1;
}
